const input = $input.first().json;
const headers = Object.fromEntries(Object.entries(input.headers ?? {}).map(([key, value]) => [key.toLowerCase(), value]));
const body = input.body ?? {};
const expectedSecret = '__N8N_SHARED_SECRET__';
const actualSecret = headers['x-n8n-shared-secret'];

if (!actualSecret) {
  throw new Error('Missing X-N8N-Shared-Secret header');
}

if (expectedSecret.startsWith('__N8N_')) {
  throw new Error('Set N8N_SHARED_SECRET before publishing this workflow');
}

if (actualSecret !== expectedSecret) {
  throw new Error('Invalid shared secret');
}

const requiredFields = ['request_id', 'notion_page_id', 'name', 'title', 'resolution', 'requester_email', 'admin_email'];
for (const field of requiredFields) {
  if (!body[field]) {
    throw new Error(`Missing required field: ${field}`);
  }
}

return [{
  json: {
    workflow: 'inquiry_complete',
    request_id: body.request_id,
    notion_page_id: body.notion_page_id,
    name: body.name,
    title: body.title,
    resolution: body.resolution,
    requester_email: body.requester_email,
    admin_email: body.admin_email,
    completed_at: new Date().toISOString()
  }
}];

